import threading
from dataclasses import dataclass
from datetime import datetime, timezone
from typing import Callable

@dataclass
class CadenceReminder:
    """Posts a reminder to the comms lead at the configured interval."""
    incident_id: str
    severity: int
    slack_channel: str
    comms_user_id: str
    notify_fn: Callable[[str, str], None]   # (channel, message) -> None
    _timer: threading.Timer | None = None

    @property
    def interval_seconds(self) -> int:
        return {1: 15 * 60, 2: 30 * 60}.get(self.severity, 30 * 60)

    def start(self) -> None:
        self._schedule_next()

    def stop(self) -> None:
        if self._timer:
            self._timer.cancel()

    def _schedule_next(self) -> None:
        self._timer = threading.Timer(self.interval_seconds, self._fire)
        self._timer.daemon = True
        self._timer.start()

    def _fire(self) -> None:
        now = datetime.now(timezone.utc).strftime('%H:%M UTC')
        msg = (
            f':bell: <@{self.comms_user_id}> Status page update due now ({now}).\n'
            f'Incident: {self.incident_id} | SEV-{self.severity}\n'
            f'Post an update even if nothing is new: '
            f'"Investigation continues, no new findings, next update in '
            f'{self.interval_seconds // 60} min."'
        )
        self.notify_fn(self.slack_channel, msg)
        self._schedule_next()   # reschedule until stop() called

import os
import requests
from dataclasses import dataclass
from enum import Enum
from typing import Optional

class ComponentStatus(Enum):
    OPERATIONAL = 'operational'
    DEGRADED = 'degraded_performance'
    PARTIAL_OUTAGE = 'partial_outage'
    MAJOR_OUTAGE = 'major_outage'

class IncidentImpact(Enum):
    NONE = 'none'
    MINOR = 'minor'
    MAJOR = 'major'
    CRITICAL = 'critical'

class IncidentStatus(Enum):
    INVESTIGATING = 'investigating'
    IDENTIFIED = 'identified'
    MONITORING = 'monitoring'
    RESOLVED = 'resolved'

@dataclass
class StatuspageClient:
    api_key: str = ''
    page_id: str = ''
    base_url: str = 'https://api.statuspage.io/v1'

    def __post_init__(self):
        if not self.api_key:
            self.api_key = os.environ['STATUSPAGE_API_KEY']
        if not self.page_id:
            self.page_id = os.environ['STATUSPAGE_PAGE_ID']

    def _headers(self) -> dict:
        return {'Authorization': f'OAuth {self.api_key}', 'Content-Type': 'application/json'}

    def create_incident(
        self,
        name: str,
        status: IncidentStatus,
        impact: IncidentImpact,
        body: str,
        component_ids: list[str],
        component_status: ComponentStatus,
    ) -> dict:
        payload = {
            'incident': {
                'name': name,
                'status': status.value,
                'impact_override': impact.value,
                'body': body,
                'components': {cid: component_status.value for cid in component_ids},
                'deliver_notifications': True,
            }
        }
        resp = requests.post(
            f'{self.base_url}/pages/{self.page_id}/incidents',
            headers=self._headers(),
            json=payload,
            timeout=10,
        )
        resp.raise_for_status()
        return resp.json()

    def post_update(
        self,
        incident_id: str,
        status: IncidentStatus,
        body: str,
        component_status: Optional[ComponentStatus] = None,
        component_ids: Optional[list[str]] = None,
    ) -> dict:
        payload: dict = {
            'incident': {'status': status.value, 'body': body}
        }
        if component_status and component_ids:
            payload['incident']['components'] = {
                cid: component_status.value for cid in component_ids
            }
        resp = requests.patch(
            f'{self.base_url}/pages/{self.page_id}/incidents/{incident_id}',
            headers=self._headers(),
            json=payload,
            timeout=10,
        )
        resp.raise_for_status()
        return resp.json()
